## services/geminiService.ts

Update the API key check to safely handle environments where `process` might not be defined globally, preventing ReferenceErrors.

```typescript
import { GoogleGenAI } from "@google/genai";

/**
 * Uses Gemini to explain the C code logic to the user.
 */
export const explainCodeLogic = async (code: string): Promise<string> => {
  // Safe access to API_KEY
  const apiKey = (typeof process !== 'undefined' && process.env) 
    ? process.env.API_KEY 
    : null;

  if (!apiKey) {
      throw new Error("API Key not found. Please check your environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey: apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `You are a senior C developer. Explain the following C code for BiDi (Bidirectional) text correction to a junior developer. 

      Focus on:
      1. Why we check for 0xD6/0xD7 for Hebrew.
      2. Why RLM (0xE2 0x80 0x8F) is added after punctuation in English context.
      3. Memory allocation strategy.

      Keep the explanation concise, bulleted, and technically accurate.

      Code:
      ${code}`,
    });

    return response.text || "No explanation generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};
```

