export const C_CODE_TEMPLATE = `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/**
 * Unicode Constants (UTF-8 encoded)
 */
const char RLE[] = "\xE2\x80\xAB"; // U+202B
const char PDF[] = "\xE2\x80\xAC"; // U+202C
const char RLM[] = "\xE2\x80\x8F"; // U+200F
const char LRE[] = "\xE2\x80\xAA"; // U+202A

// Hebrew Native Punctuation (UTF-8)
const char HEB_MAQAF[]    = "\xD6\xBE"; // ־ (U+05BE)
const char HEB_GERESH[]   = "\xD7\xB3"; // ׳ (U+05F3)
const char HEB_GERSHAYIM[] = "\xD7\xB4"; // ״ (U+05F4)

/**
 * Advanced BiDi Fixer:
 * 1. Wraps segments in RLE/PDF.
 * 2. Replaces standard quotes/dashes with native Hebrew equivalents.
 * 3. Handles English runs with LRE.
 */
char* fix_bidi_full_native(const char* input) {
    if (!input) return NULL;

    // Buffer allocation (4x input size for safety with UTF-8 expansion)
    size_t in_len = strlen(input);
    char* output = (char*)malloc(in_len * 5 + 10);
    if (!output) return NULL;

    size_t o = 0;
    int in_english = 0;

    // Start Global RTL
    memcpy(output + o, RLE, 3); o += 3;

    for (size_t i = 0; i < in_len; i++) {
        unsigned char c = (unsigned char)input[i];

        // Context switching
        if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9')) {
            if (!in_english) {
                memcpy(output + o, LRE, 3); o += 3;
                in_english = 1;
            }
        } else if (c >= 0xD6 && c <= 0xD7) { // Hebrew start byte
            if (in_english) {
                memcpy(output + o, PDF, 3); o += 3;
                in_english = 0;
            }
        }

        // Native Character Replacement (only in Hebrew context)
        if (!in_english) {
            if (c == '"') {
                memcpy(output + o, HEB_GERSHAYIM, 2); o += 2;
                continue;
            } else if (c == '\'') {
                memcpy(output + o, HEB_GERESH, 2); o += 2;
                continue;
            } else if (c == '-') {
                memcpy(output + o, HEB_MAQAF, 2); o += 2;
                continue;
            }
        }

        output[o++] = input[i];

        // Add RLM after punctuation in Hebrew context
        if (!in_english && strchr(".,?!:;()", c)) {
            memcpy(output + o, RLM, 3); o += 3;
        }
    }

    if (in_english) { memcpy(output + o, PDF, 3); o += 3; }
    memcpy(output + o, PDF, 3); o += 3; // Close Global
    output[o] = '\0';

    return output;
}

int main() {
    const char* text = "אמרתי לו \"שלום\" ו-123 חברים.";
    char* fixed = fix_bidi_full_native(text);
    printf("Fixed: %s\n", fixed);
    free(fixed);
    return 0;
}`;

