   * 4. Native quote/dash replacements.
   */
  const deepBidiAlgorithm = (text: string) => {
      let resultText = RLE; 
      let inEnglishRun = false;
      let currentContextIsHebrew = true;
      const chunkStats = { rlmAdded: 0, nativeCharsSet: 0, totalChars: 0 };

      // Normalize spaces
      const normalized = text.split('\u00A0').join(' ');

      for (let i = 0; i < normalized.length; i++) {
        const char = normalized[i];
        chunkStats.totalChars++;

        const isEnglish = ENGLISH_ALNUM_REGEX.test(char);
        const isHebrew = HEBREW_REGEX.test(char);

        // State Machine for Directional Context
        if (isEnglish && !inEnglishRun) {
            resultText += LRE;
            inEnglishRun = true;
            currentContextIsHebrew = false;
        } else if (isHebrew && inEnglishRun) {
            resultText += PDF;
            inEnglishRun = false;
            currentContextIsHebrew = true;
        }

        // Process characters in Hebrew Context
        if (currentContextIsHebrew) {
            // 1. Bracket Sandwich (Crucial for Word)
            if (BRACKETS.has(char)) {
                resultText += RLM + char + RLM;
                chunkStats.rlmAdded += 2;
                continue;
            }

            // 2. Colon/Semicolon Anchor
            if (char === ':' || char === ';') {
                resultText += char + RLM;
                chunkStats.rlmAdded++;
                continue;
            }

            // 3. Native Hebrew Punctuation
            if (char === '"') {
                resultText += HEB_GERSHAYIM;
                chunkStats.nativeCharsSet++;
                continue;
            } else if (char === "'") {
                resultText += HEB_GERESH;
                chunkStats.nativeCharsSet++;
                continue;
            } else if (char === '-') {
                resultText += HEB_MAQAF;
                chunkStats.nativeCharsSet++;
                continue;
            }

            // 4. Dot/Comma/Question/Exclamation Anchoring
            if (ANCHOR_PUNCTUATION.has(char)) {
                resultText += char + RLM;
                chunkStats.rlmAdded++;
                continue;
            }
        }

        resultText += char;
      }

      if (inEnglishRun) resultText += PDF;
      resultText += PDF; 

      return { fixedText: resultText, chunkStats };
  };

  const runPipeline = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;

    const blocks = container.querySelectorAll('p, div, li, h1, h2, h3, h4, h5, h6, span');
    blocks.forEach(block => {
        const el = block as HTMLElement;
        el.setAttribute('dir', 'rtl');
        el.setAttribute('lang', 'he-IL');
        el.style.direction = 'rtl';
        el.style.textAlign = 'right';
        el.style.unicodeBidi = 'embed';
    });

    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let fullRawText = '';
    const totalStats: FixStats = { rlmAdded: 0, nativeCharsSet: 0, totalChars: 0 };

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          const result = deepBidiAlgorithm(originalText);
          totalStats.rlmAdded += result.chunkStats.rlmAdded;
          totalStats.nativeCharsSet += result.chunkStats.nativeCharsSet;
          totalStats.totalChars += result.chunkStats.totalChars;
          currentNode.nodeValue = result.fixedText;
          fullRawText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    return { 
        html: container.innerHTML, 
        text: fullRawText, 
        stats: totalStats 
    };
  };

