            {isProcessing && !magicSuccess ? <span className="animate-spin">⌛</span> : <Check size={18} />}
            תקן הכל (סוגריים ופיסוק)
         </button>
         <button onClick={handleMagic} disabled={isProcessing} className="bg-gradient-to-r from-indigo-600 to-blue-600 hover:from-indigo-700 hover:to-blue-700 text-white px-10 py-3 rounded-full shadow-xl shadow-blue-500/20 flex items-center gap-2 font-bold transition-all hover:scale-105 active:scale-95 disabled:opacity-70 overflow-hidden">
            {isProcessing ? <span className="animate-spin">⌛</span> : magicSuccess ? <span className="animate-bounce">✨ בוצע!</span> : <><Sparkles size={18} className="text-yellow-300" /> MAGIC FIX</>}
         </button>
