    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
    <meta charset="utf-8">
    <style>
        body { 
            direction: rtl; 
            text-align: right; 
            font-family: "Arial", "Times New Roman", serif; 
        }
        p, div, li, span { 
            direction: rtl; 
            unicode-bidi: embed; 
            text-align: right; 
            mso-direction-alt: rtl;
            mso-font-charset: 177; /* Hebrew Charset */
        }
    </style>
    </head>
    <body lang="he-IL" style="direction: rtl; text-align: right;">
        <div dir="rtl" lang="he-IL" style="direction: rtl; text-align: right; unicode-bidi: embed;">
            ${content}
        </div>
    </body>
    </html>`.trim();
};

interface FixStats {
    rlmAdded: number;
    nativeCharsSet: number;
    totalChars: number;
}

export const BidiFixer: React.FC = () => {
  const [inputHtml, setInputHtml] = useState<string>(''); 
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [copied, setCopied] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [magicSuccess, setMagicSuccess] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (viewMode === 'formatted' && outputFormattedRef.current && outputRichHtml) {
        if (outputFormattedRef.current.innerHTML !== outputRichHtml) {
            outputFormattedRef.current.innerHTML = outputRichHtml;
        }
    }
  }, [viewMode, outputRichHtml]);

  /**
   * ULTIMATE BIDI ALGORITHM (Keyboard-Style):
   * Goes Char-by-Char to replace punctuation and protect weak characters.
   */
  const ultimateBidiAlgorithm = (text: string) => {
      let resultText = RLE; // Global RTL
      let inEnglishRun = false;
      let currentContextIsHebrew = true;
      const chunkStats = { rlmAdded: 0, nativeCharsSet: 0, totalChars: 0 };

      const normalized = text.split('\u00A0').join(' ');

      for (let i = 0; i < normalized.length; i++) {
        const char = normalized[i];
        chunkStats.totalChars++;

        const isEnglish = ENGLISH_ALNUM_REGEX.test(char);
        const isHebrew = HEBREW_REGEX.test(char);

        // 1. Context Switch
        if (isEnglish && !inEnglishRun) {
            resultText += LRE;
            inEnglishRun = true;
            currentContextIsHebrew = false;
        } else if (isHebrew && inEnglishRun) {
            resultText += PDF + RLM; // End LTR and return to RTL
            inEnglishRun = false;
            currentContextIsHebrew = true;
        }

        // 2. Hebrew Context Character Logic
        if (currentContextIsHebrew) {
            // Brackets Sandwich: RLM + ( + RLM
            if (BRACKETS.has(char)) {
                resultText += RLM + char + RLM;
                chunkStats.rlmAdded += 2;
                continue;
            }

            // Native Hebrew Punctuation (Geresh, Gershayim, Maqaf)
            if (char === '"') {
                resultText += HEB_GERSHAYIM;
                chunkStats.nativeCharsSet++;
                continue;
            } else if (char === "'") {
                resultText += HEB_GERESH;
                chunkStats.nativeCharsSet++;
                continue;
            } else if (char === '-') {
                resultText += HEB_MAQAF;
                chunkStats.nativeCharsSet++;
                continue;
            }

            // Anchor neutral symbols with RLM
            if (NEUTRAL_ANCHOR.has(char)) {
                resultText += char + RLM;
                chunkStats.rlmAdded++;
                continue;
            }
        }

        resultText += char;
      }

      if (inEnglishRun) resultText += PDF;
      resultText += PDF; 

      return { fixedText: resultText, chunkStats };
  };

  const runPipeline = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;

    const blocks = container.querySelectorAll('p, div, li, h1, h2, h3, h4, h5, h6, span');
    blocks.forEach(block => {
        const el = block as HTMLElement;
        el.setAttribute('dir', 'rtl');
        el.setAttribute('lang', 'he-IL');
        el.style.direction = 'rtl';
        el.style.textAlign = 'right';
        el.style.unicodeBidi = 'embed';
    });

    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let fullRawText = '';
    const totalStats: FixStats = { rlmAdded: 0, nativeCharsSet: 0, totalChars: 0 };

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          const result = ultimateBidiAlgorithm(originalText);
          totalStats.rlmAdded += result.chunkStats.rlmAdded;
          totalStats.nativeCharsSet += result.chunkStats.nativeCharsSet;
          totalStats.totalChars += result.chunkStats.totalChars;
          currentNode.nodeValue = result.fixedText;
          fullRawText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    return { 
        html: container.innerHTML, 
        text: fullRawText, 
        stats: totalStats 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    setTimeout(() => {
        if (inputRef.current) {
            const result = runPipeline(inputRef.current.innerHTML);
            setOutputText(result.text);
            setOutputRichHtml(result.html);
            setStats(result.stats);
            setViewMode('formatted');
        }
        setIsProcessing(false);
    }, 300);
  };

  const handleMagic = async () => {
    setIsProcessing(true);
    try {
        const clipboardItems = await navigator.clipboard.read();
        let content = '';
        for (const item of clipboardItems) {
            if (item.types.includes('text/html')) content = await (await item.getType('text/html')).text();
            else if (item.types.includes('text/plain')) content = await (await item.getType('text/plain')).text();
        }
        if (!content) return alert('הלוח ריק!');

        setInputHtml(content);
        if (inputRef.current) inputRef.current.innerHTML = content;

        const result = runPipeline(content);
        setOutputText(result.text);
        setOutputRichHtml(result.html);
        setStats(result.stats);

        const fullHtml = getWordFriendlyHtml(result.html);
        const data = [new ClipboardItem({
            'text/html': new Blob([fullHtml], { type: 'text/html' }),
            'text/plain': new Blob([result.text], { type: 'text/plain' }),
        })];
        await navigator.clipboard.write(data);
        setMagicSuccess(true);
        setTimeout(() => setMagicSuccess(false), 3000);
    } catch (err) {
        console.error(err);
        alert('שגיאה בלוח');
    } finally {
        setIsProcessing(false);
    }
  };

  const handleCopyWord = async () => {
    try {
        const currentRichHtml = outputFormattedRef.current?.innerHTML || outputRichHtml;
        const currentPlainText = outputText; 
        const fullHtmlForWord = getWordFriendlyHtml(currentRichHtml);

        const data = [new ClipboardItem({
            'text/html': new Blob([fullHtmlForWord], { type: 'text/html' }),
            'text/plain': new Blob([currentPlainText], { type: 'text/plain' }),
        })];

        await navigator.clipboard.write(data);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    } catch (err) {
        console.error(err);
    }
  };

  return (
    <div className="flex flex-col gap-8 max-w-4xl mx-auto pb-20">

      {/* INPUT */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col overflow-hidden focus-within:ring-2 focus-within:ring-blue-500/20">
        <div className="bg-slate-50/50 border-b border-slate-100 px-4 py-3 flex justify-between items-center">
            <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                טקסט מקור (ChatGPT / Claude)
            </label>
            <div className="flex items-center gap-4">
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 transition-colors text-xs flex items-center gap-1">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגת RTL' : 'תצוגת קוד'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setInputHtml('');}} className="text-xs text-slate-400 hover:text-red-500 transition-colors flex items-center gap-1">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[160px] p-6 text-lg leading-relaxed text-slate-800 focus:outline-none overflow-y-auto max-h-[500px]"
            onInput={(e) => setInputHtml(e.currentTarget.innerHTML)}
            spellCheck={false}
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
        />
      </div>

      {/* ACTIONS */}
      <div className="flex justify-center -my-4 z-10 gap-4">
         <button onClick={handleFix} disabled={isProcessing} className="bg-white text-blue-600 border border-blue-200 hover:bg-blue-50 px-8 py-3 rounded-full shadow-lg flex items-center gap-2 font-bold transition-all active:scale-95 disabled:opacity-70">
            {isProcessing && !magicSuccess ? <span className="animate-spin">⌛</span> : <Check size={18} />}
            תיקון CHAR BY CHAR
         </button>
         <button onClick={handleMagic} disabled={isProcessing} className="bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white px-10 py-3 rounded-full shadow-xl shadow-blue-500/20 flex items-center gap-2 font-bold transition-all hover:scale-105 active:scale-95 disabled:opacity-70 overflow-hidden">
            {isProcessing ? <span className="animate-spin">⌛</span> : magicSuccess ? <span className="animate-bounce">✨ בוצע!</span> : <><Sparkles size={18} className="text-yellow-300" /> MAGIC FIX</>}
         </button>
      </div>

      {/* OUTPUT */}
      <div className="flex flex-col gap-3">
          <div className="flex justify-between items-center px-1">
              <div className="flex gap-1 bg-slate-200/50 p-1 rounded-lg">
                  <button onClick={() => setViewMode('formatted')} className={`flex items-center gap-1.5 px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'formatted' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}>
                      <FileText size={14} /> תצוגת עריכה
                  </button>
                  <button onClick={() => setViewMode('raw')} className={`flex items-center gap-1.5 px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'raw' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}>
                      <Code size={14} /> UTF-8 Debug
                  </button>
              </div>
              <div className="flex gap-3 text-[11px] text-slate-400">
                  {stats && (
                      <span className="flex items-center gap-1 bg-white border border-slate-100 px-2 py-0.5 rounded shadow-sm">
                          <Hash size={12} /> {stats.nativeCharsSet} תווים הוחלפו לעברית | {stats.rlmAdded} עגני כיווניות
                      </span>
                  )}
              </div>
          </div>

          <div className="relative group">
             {viewMode === 'raw' ? (
                 <div className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 font-mono text-xs text-blue-300 overflow-x-auto min-h-[150px] whitespace-pre-wrap" dir="ltr">
                     {JSON.stringify({ 
                         "algorithm": "Deep Native Character Replacement + Bracket Isolation",
                         "text": outputText
                     }, null, 2)}
                 </div>
             ) : (
                 <div 
                    ref={outputFormattedRef}
                    contentEditable
                    className="w-full bg-white border border-slate-300 rounded-xl px-6 py-6 text-slate-900 text-lg leading-relaxed overflow-y-auto editor-content min-h-[180px] focus:ring-2 focus:ring-blue-500 outline-none shadow-inner"
                    dir="rtl"
                    lang="he-IL"
                    onInput={(e) => setOutputRichHtml(e.currentTarget.innerHTML)}
                 />
             )}
          </div>

          <div className="flex flex-col md:flex-row justify-between items-center mt-2 gap-4">
               <p className="text-xs text-slate-500 flex items-center gap-2">
                   <AlertCircle size={14} className="text-blue-500" />
                   כל סוגר ( ו- ) בודד כעת בתוך כריך RLM. סימני מרכאות ומקף הוחלפו לתווים עבריים תקניים.
               </p>

               <button
                    onClick={handleCopyWord}
                    disabled={!outputRichHtml}
                    className={`group relative flex items-center gap-3 px-10 py-4 rounded-xl text-base font-black transition-all shadow-lg active:translate-y-0.5 ${copied ? 'bg-emerald-500 text-white shadow-emerald-200' : 'bg-slate-900 text-white hover:bg-black shadow-slate-200'}`}
               >
                    {copied ? <ClipboardCheck size={20} className="animate-bounce" /> : <Copy size={20} className="group-hover:scale-110 transition-transform" />}
                    {copied ? 'הועתק ל-Word!' : 'העתקה מושלמת ל-Word'}

                    {!copied && (
                        <span className="absolute -top-3 -right-3 bg-blue-600 text-white text-[10px] px-2.5 py-1 rounded-full border-2 border-white shadow-md font-bold">
                            NATIVE FIX
                        </span>
                    )}
               </button>
          </div>
      </div>
    </div>
  );
};

export const C_CODE_TEMPLATE = `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/**
 * Unicode Constants (UTF-8 encoded)
 */
const char RLM[] = "\xE2\x80\x8F"; // U+200F (Right-to-Left Mark)

// Hebrew Native Punctuation (Unicode Block U+0590)
const char HEB_MAQAF[]    = "\xD6\xBE"; // ־ (U+05BE)
const char HEB_GERESH[]   = "\xD7\xB3"; // ׳ (U+05F3)
const char HEB_GERSHAYIM[] = "\xD7\xB4"; // ״ (U+05F4)

/**
 * The "Native Keyboard" Fix:
 * 1. Replaces ASCII punctuation with Hebrew counterparts.
 * 2. Adds RLM after colons/brackets to anchor them to the RTL flow.
 */
char* fix_bidi_native(const char* input) {
    if (!input) return NULL;

    size_t in_len = strlen(input);
    // Buffer for expansion (UTF-8 chars and RLMs)
    char* output = (char*)malloc(in_len * 4 + 1);
    if (!output) return NULL;

    size_t o = 0;
    for (size_t i = 0; i < in_len; i++) {
        unsigned char c = (unsigned char)input[i];

        // Replace with Native Hebrew Characters
        if (c == '"') {
            memcpy(output + o, HEB_GERSHAYIM, 2); o += 2;
            continue;
        } else if (c == '\'') {
            memcpy(output + o, HEB_GERESH, 2); o += 2;
            continue;
        } else if (c == '-') {
            memcpy(output + o, HEB_MAQAF, 2); o += 2;
            continue;
        }

        // Standard copy
        output[o++] = input[i];

        // Anchor weak punctuation (Colons, Brackets, Dots)
        if (strchr("():;.,?!", c)) {
            memcpy(output + o, RLM, 3); o += 3;
        }
    }

    output[o] = '\0';
    return output;
}

int main() {
    const char* text = "בדיקה (סוגריים) ונקודתיים: וגם \"מרכאות\".";
    char* fixed = fix_bidi_native(text);
    printf("Result: %s\n", fixed);
    free(fixed);
    return 0;
}`;

import React, { useState, useRef, useEffect } from 'react';
import { Copy, Check, Eraser, Hash, AlertCircle, Eye, EyeOff, FileText, Code, Sparkles, ClipboardCheck, ClipboardCopy } from 'lucide-react';

// Unicode Control Characters
const RLM = '\u200F';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!', '(', ')', '[', ']', '{', '}']);

/**
 * Simplified HTML for Word - Minimalist and robust
 */
const getWordFriendlyHtml = (content: string) => {
    return `
    <div dir="rtl" style="direction: rtl; text-align: right; font-family: Arial, sans-serif;">
        ${content}
    </div>`.trim();
};

interface FixStats {
    replaced: number;
    anchored: number;
}

export const BidiFixer: React.FC = () => {
  const [inputHtml, setInputHtml] = useState<string>(''); 
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [copied, setCopied] = useState<'rich' | 'plain' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  // Core algorithm: Clean Native Replacement
  const cleanBidiAlgorithm = (text: string) => {
      let resultText = ''; 
      let replaced = 0;
      let anchored = 0;

      // Normalize non-breaking spaces
      const normalized = text.split('\u00A0').join(' ');

      for (let i = 0; i < normalized.length; i++) {
        const char = normalized[i];

        // 1. Character replacement (Native Hebrew)
        if (char === '"') {
            resultText += HEB_GERSHAYIM;
            replaced++;
            continue;
        } else if (char === "'") {
            resultText += HEB_GERESH;
            replaced++;
            continue;
        } else if (char === '-') {
            resultText += HEB_MAQAF;
            replaced++;
            continue;
        }

        resultText += char;

        // 2. Anchoring weak symbols to RTL context
        if (WEAK_PUNCTUATION.has(char)) {
            resultText += RLM;
            anchored++;
        }
      }

      return { fixedText: resultText, stats: { replaced, anchored } };
  };

  const processContent = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;

    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let totalReplaced = 0;
    let totalAnchored = 0;
    let fullPlainText = '';

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          const result = cleanBidiAlgorithm(originalText);
          totalReplaced += result.stats.replaced;
          totalAnchored += result.stats.anchored;
          currentNode.nodeValue = result.fixedText;
          fullPlainText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    return { 
        html: container.innerHTML, 
        text: fullPlainText, 
        stats: { replaced: totalReplaced, anchored: totalAnchored } 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    setTimeout(() => {
        const currentHtml = inputRef.current?.innerHTML || '';
        const result = processContent(currentHtml);
        setOutputText(result.text);
        setOutputRichHtml(result.html);
        setStats(result.stats);
        setViewMode('formatted');
        setIsProcessing(false);
    }, 200);
  };

  const handleCopyRich = async () => {
    const richContent = outputFormattedRef.current?.innerHTML || outputRichHtml;
    const wordHtml = getWordFriendlyHtml(richContent);
    const data = [new ClipboardItem({
        'text/html': new Blob([wordHtml], { type: 'text/html' }),
        'text/plain': new Blob([outputText], { type: 'text/plain' }),
    })];
    await navigator.clipboard.write(data);
    setCopied('rich');
    setTimeout(() => setCopied(null), 2000);
  };

  const handleCopyPlain = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-6 max-w-4xl mx-auto pb-20">

      {/* INPUT */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col overflow-hidden">
        <div className="bg-slate-50 border-b border-slate-100 px-4 py-2.5 flex justify-between items-center">
            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">טקסט מקור</span>
            <div className="flex gap-4">
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 transition-colors text-xs flex items-center gap-1">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'תצוגת קוד'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText('');}} className="text-xs text-slate-400 hover:text-red-500 flex items-center gap-1">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[140px] p-5 text-lg leading-relaxed text-slate-800 focus:outline-none max-h-[400px] overflow-y-auto"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
      </div>

      {/* ACTION */}
      <div className="flex justify-center -my-3 z-10">
         <button onClick={handleFix} disabled={isProcessing} className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-3.5 rounded-full shadow-xl flex items-center gap-2 font-bold transition-all active:scale-95 disabled:opacity-70">
            {isProcessing ? <span className="animate-spin text-lg">⌛</span> : <Wand2 size={20} />}
            תיקון תווים עבריים (Clean Fix)
         </button>
      </div>

      {/* OUTPUT */}
      <div className="flex flex-col gap-3">
          <div className="flex justify-between items-end px-1">
              <div className="flex gap-1 bg-slate-200/50 p-1 rounded-lg">
                  <button onClick={() => setViewMode('formatted')} className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'formatted' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}>
                      תצוגה מקדימה
                  </button>
                  <button onClick={() => setViewMode('raw')} className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'raw' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}>
                      קוד UTF-8
                  </button>
              </div>
              {stats && (
                <div className="text-[10px] text-slate-400 font-mono bg-white px-2 py-1 rounded border border-slate-100">
                    REPLACED: {stats.replaced} | ANCHORED: {stats.anchored}
                </div>
              )}
          </div>

          <div className="bg-white border border-slate-300 rounded-xl overflow-hidden shadow-sm">
             {viewMode === 'raw' ? (
                 <pre className="p-5 font-mono text-xs text-slate-600 bg-slate-50 min-h-[150px] whitespace-pre-wrap overflow-x-auto" dir="ltr">
                     {outputText}
                 </pre>
             ) : (
                 <div 
                    ref={outputFormattedRef}
                    contentEditable
                    className="p-6 text-slate-900 text-lg leading-relaxed min-h-[150px] focus:outline-none"
                    dir="rtl"
                    onInput={(e) => setOutputRichHtml(e.currentTarget.innerHTML)}
                 />
             )}
          </div>

          <div className="flex flex-col sm:flex-row gap-3 mt-2">
               <button
                    onClick={handleCopyRich}
                    disabled={!outputRichHtml && !outputText}
                    className={`flex-1 flex items-center justify-center gap-2 py-3.5 rounded-xl font-bold transition-all shadow-md ${copied === 'rich' ? 'bg-emerald-500 text-white' : 'bg-slate-900 text-white hover:bg-black'}`}
               >
