export const explainCodeLogic = async (code: string): Promise<string> => {
  // NOTE: process.env.API_KEY is expected to be available in the build environment.
  // In a real production app, this would likely be proxied through a backend.
  if (!process.env.API_KEY) {
      throw new Error("API Key not found");
  }

  // Initializing GoogleGenAI with apiKey from process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Using gemini-3-flash-preview for text analysis task
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a senior C developer. Explain the following C code for BiDi (Bidirectional) text correction to a junior developer. 

      Focus on:
      1. Why we check for 0xD6/0xD7 for Hebrew.
      2. Why RLM (0xE2 0x80 0x8F) is added after punctuation in English context.
      3. Memory allocation strategy.

      Keep the explanation concise, bulleted, and technically accurate.

      Code:
      ${code}`,
    });

    // response.text is a property, not a method
    return response.text || "No explanation generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const C_CODE_TEMPLATE = `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/**
 * Unicode Control Characters (UTF-8 encoded)
 */
const char RLE[] = "\xE2\x80\xAB"; // U+202B (Start Right-to-Left Embedding)
const char PDF[] = "\xE2\x80\xAC"; // U+202C (Pop Directional Formatting)
const char RLM[] = "\xE2\x80\x8F"; // U+200F (Right-to-Left Mark)

// Hebrew Native Punctuation (Unicode Block U+0590)
const char HEB_MAQAF[]    = "\xD6\xBE"; // ־ (U+05BE)
const char HEB_GERESH[]   = "\xD7\xB3"; // ׳ (U+05F3)
const char HEB_GERSHAYIM[] = "\xD7\xB4"; // ״ (U+05F4)

/**
 * The "Ultimate BiDi" Fix:
 * 1. Wraps the entire output in RLE...PDF for global context.
 * 2. Replaces ASCII quotes/dashes with Native Hebrew characters.
 * 3. Uses the "Sandwich" technique for brackets: RLM + bracket + RLM.
 * 4. Anchors colons and other neutrals with a trailing RLM.
 */
char* fix_bidi_ultimate(const char* input) {
    if (!input) return NULL;

    size_t in_len = strlen(input);
    // Buffer for expansion: RLE + PDF + RLM sandwiches + UTF-8 chars
    // Allocating roughly 10x the input size to be safe.
    char* output = (char*)malloc(in_len * 10 + 16);
    if (!output) return NULL;

    size_t o = 0;

    // Global RTL Wrap
    memcpy(output + o, RLE, 3); o += 3;

    for (size_t i = 0; i < in_len; i++) {
        unsigned char c = (unsigned char)input[i];

        // 1. Brackets Sandwich (Forcing Hebrew directionality on neutral chars)
        if (strchr("()[]{}<>", c)) {
            memcpy(output + o, RLM, 3); o += 3;
            output[o++] = c;
            memcpy(output + o, RLM, 3); o += 3;
            continue;
        }

        // 2. Native Character Replacement
        if (c == '"') {
            memcpy(output + o, HEB_GERSHAYIM, 2); o += 2;
            continue;
        } else if (c == '\'') {
            memcpy(output + o, HEB_GERESH, 2); o += 2;
            continue;
        } else if (c == '-') {
            memcpy(output + o, HEB_MAQAF, 2); o += 2;
            continue;
        }

        // 3. Normal Copy
        output[o++] = input[i];

        // 4. Anchoring Neutrals (Colon, Semicolon, etc.)
        if (strchr(":;.,?!", c)) {
            memcpy(output + o, RLM, 3); o += 3;
        }
    }

    // Close RTL Wrap
    memcpy(output + o, PDF, 3); o += 3;
    output[o] = '\0';

    return output;
}

int main() {
    const char* text = "עברית (English) וסימנים: \"מרכאות\".";
    char* fixed = fix_bidi_ultimate(text);
    printf("Fixed: %s\n", fixed);
    free(fixed);
    return 0;
}`;

