        })];

        await navigator.clipboard.write(data);
        setCopied('rich');
        setTimeout(() => setCopied(null), 2000);
    } catch (err) {
        console.error("Clipboard Rich error:", err);
        // Fallback to text copy
        handleCopyPlain();
    }
  };

  const handleCopyPlain = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

