                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'תצוגת קוד'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText(''); setOutputRichHtml(''); setStats(null);}} className="text-xs text-slate-400 hover:text-red-500 flex items-center gap-1">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[160px] p-5 text-lg leading-relaxed text-slate-800 focus:outline-none max-h-[400px] overflow-y-auto"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
            onInput={(e) => setInputHtml(e.currentTarget.innerHTML)}
        />
      </div>

      {/* ACTION BUTTON */}
      <div className="flex justify-center -my-3 z-10">
         <button onClick={handleFix} disabled={isProcessing} className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-4 rounded-full shadow-xl flex items-center gap-3 font-black transition-all active:scale-95 disabled:opacity-70 group">
            {isProcessing ? <span className="animate-spin text-lg">⌛</span> : <Wand2 size={22} className="group-hover:rotate-12 transition-transform" />}
            תיקון כיווניות עמוק (ULTRA FIX)
         </button>
      </div>

      {/* OUTPUT AREA */}
      <div className="flex flex-col gap-3">
          <div className="flex justify-between items-end px-1">
              <div className="flex gap-1 bg-slate-200/50 p-1 rounded-lg">
                  <button onClick={() => setViewMode('formatted')} className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'formatted' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}>
                      תצוגה מקדימה
                  </button>
                  <button onClick={() => setViewMode('raw')} className={`px-4 py-1.5 rounded-md text-xs font-bold transition-all ${viewMode === 'raw' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}>
