// Unicode Control Characters
const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

// מאגר עובדות מעניינות על שפות ופורמטים
const LANGUAGE_FACTS = [
  {
    title: "ISO-8859-8",
    content: "לפני עידן ה-Unicode, תקן ISO-8859-8 שימש לעברית. היו לו שתי גרסאות: 'לוגית' (שבה כותבים כפי שקוראים) ו'ויזואלית' (שבה היה צריך להקליד הפוך כדי שהטקסט יוצג נכון)."
  },
  {
