                <Languages size={16} className="text-blue-500" />
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">טקסט מקור (ChatGPT / Claude)</span>
            </div>
            <div className="flex gap-4">
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 transition-colors text-xs flex items-center gap-1.5">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'תצוגת קוד'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText(''); setOutputRichHtml(''); setStats(null); setActiveFact(null);}} className="text-xs text-slate-400 hover:text-red-500 flex items-center gap-1.5 transition-colors">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[180px] p-6 text-lg leading-relaxed text-slate-800 focus:outline-none max-h-[400px] overflow-y-auto"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
      </div>

      {/* ACTION BUTTON */}
      <div className="flex justify-center -my-4 z-10 relative">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-4.5 rounded-full shadow-xl flex items-center gap-3 font-black transition-all active:scale-95 hover:scale-105 disabled:opacity-70 group overflow-hidden"
         >
            <div className={`absolute inset-0 bg-white/20 transition-transform duration-1000 ${isProcessing ? 'translate-x-full' : '-translate-x-full'}`} />
            {isProcessing ? <span className="animate-spin text-xl">⌛</span> : <Wand2 size={24} className="group-hover:rotate-12 transition-transform" />}
            תיקון כיווניות עמוק
         </button>
      </div>

      {/* OUTPUT AREA */}
      <div className="flex flex-col gap-4">
          <div className="flex justify-between items-end px-1">
              <div className="flex gap-1 bg-slate-200/50 p-1 rounded-lg">
                  <button onClick={() => setViewMode('formatted')} className={`px-5 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'formatted' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
