                      <ArrowRightLeft size={24} className="text-blue-500 mb-2 group-hover:scale-110 transition-transform" />
                      <span className="text-2xl font-black text-slate-800">{stats.replaced}</span>
                      <span className="text-[10px] font-black text-slate-400 uppercase">החלפות תווים</span>
                  </div>
                  <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center justify-center text-center group hover:border-amber-200 transition-colors">
                      <Zap size={24} className="text-amber-500 mb-2 group-hover:scale-110 transition-transform" />
                      <span className="text-2xl font-black text-slate-800">{stats.anchored}</span>
                      <span className="text-[10px] font-black text-slate-400 uppercase">עוגני כיווניות</span>
                  </div>
                  <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center justify-center text-center group hover:border-emerald-200 transition-colors overflow-hidden relative">
                      <div className="absolute top-0 right-0 w-12 h-12 bg-emerald-50 rounded-bl-full -mr-4 -mt-4 opacity-50 group-hover:scale-150 transition-transform" />
                      <Sparkles size={24} className="text-emerald-500 mb-2 group-hover:scale-110 transition-transform" />
                      <span className="text-2xl font-black text-slate-800">{stats.interventionRate.toFixed(1)}%</span>
                      <span className="text-[10px] font-black text-slate-400 uppercase">אופטימיזציה</span>
                  </div>
              </div>

              {/* Fact Card */}
              {activeFact && (
                  <div className="bg-white border border-blue-100 p-6 rounded-2xl shadow-sm flex flex-col md:flex-row gap-5 items-center md:items-start group transition-all hover:shadow-md hover:border-blue-200">
                      <div className="bg-blue-600 p-3.5 rounded-2xl text-white shadow-lg shadow-blue-100 shrink-0 group-hover:rotate-6 transition-transform">
                          <Globe2 size={28} />
                      </div>
                      <div className="space-y-2 text-center md:text-right">
                          <div className="flex flex-col md:flex-row items-center gap-3">
                              <h4 className="font-black text-slate-900 text-base">הידעת? עובדת שפה וטכנולוגיה</h4>
                              <span className="text-blue-600 px-3 py-1 bg-blue-50 rounded-full text-[10px] font-bold border border-blue-100 uppercase tracking-wide">
                                  {activeFact.title}
                              </span>
                          </div>
                          <p className="text-sm text-slate-600 leading-relaxed max-w-2xl">
                              {activeFact.content}
                          </p>
                      </div>
                  </div>
              )}
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, AlertCircle, Eye, EyeOff, ClipboardCheck, 
  ClipboardCopy, Wand2, BarChart3, Languages, Globe2, 
  Zap, ArrowRightLeft, Hash, Info, Sparkles, BookOpen, Cpu
} from 'lucide-react';

// Unicode Control Characters
const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

// מאגר מורחב של עובדות מעניינות (20+)
