              )}

              {/* Bottom Decoration */}
              <div className="flex justify-center items-center gap-1.5 opacity-20 py-4">
                  <div className="w-1 h-1 bg-slate-400 rounded-full" />
                  <div className="w-1 h-1 bg-slate-400 rounded-full" />
                  <Cpu size={12} className="text-slate-400" />
                  <div className="w-1 h-1 bg-slate-400 rounded-full" />
                  <div className="w-1 h-1 bg-slate-400 rounded-full" />
              </div>
          </div>
      </div>
    </div>
  );
};

