const getWordFriendlyHtml = (content: string) => {
    return `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head><meta charset="utf-8"></head>
    <body lang="he-IL" style="direction: rtl; text-align: right;">
        <div dir="rtl" style="direction: rtl; text-align: right; font-family: 'Segoe UI', Arial, sans-serif;">
            ${content}
        </div>
    </body>
    </html>`.trim();
};

interface FixStats {
    totalChars: number;
    replaced: number;
    anchored: number;
    interventionRate: number;
}

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [activeFact, setActiveFact] = useState<typeof LANGUAGE_FACTS[0] | null>(null);
  const [copied, setCopied] = useState<'rich' | 'plain' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  const ultimateBidiAlgorithm = (text: string) => {
      let resultText = RLE;
      let replacedCount = 0;
      let anchoredCount = 0;

      const normalized = text.split('\u00A0').join(' ');

      for (let i = 0; i < normalized.length; i++) {
        const char = normalized[i];

        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            anchoredCount += 2;
            continue;
        }

        if (char === '"') {
            resultText += HEB_GERSHAYIM;
            replacedCount++;
            continue;
        } else if (char === "'") {
            resultText += HEB_GERESH;
            replacedCount++;
            continue;
        } else if (char === '-') {
            resultText += HEB_MAQAF;
            replacedCount++;
            continue;
        }

        resultText += char;

        if (WEAK_PUNCTUATION.has(char)) {
            resultText += RLM;
            anchoredCount++;
        }
      }

      resultText += PDF;
      return { fixedText: resultText, replaced: replacedCount, anchored: anchoredCount };
  };

  const processContent = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;

    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let totalReplaced = 0;
    let totalAnchored = 0;
    let totalChars = 0;
    let fullPlainText = '';

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          totalChars += originalText.length;
          const result = ultimateBidiAlgorithm(originalText);
          totalReplaced += result.replaced;
          totalAnchored += result.anchored;
          currentNode.nodeValue = result.fixedText;
          fullPlainText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    const interventionRate = totalChars > 0 ? ((totalReplaced + totalAnchored) / totalChars) * 100 : 0;

    return { 
        html: container.innerHTML, 
        text: fullPlainText, 
        stats: { totalChars, replaced: totalReplaced, anchored: totalAnchored, interventionRate } 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    const randomFact = LANGUAGE_FACTS[Math.floor(Math.random() * LANGUAGE_FACTS.length)];

    setTimeout(() => {
        const currentHtml = inputRef.current?.innerHTML || '';
        const result = processContent(currentHtml);
        setOutputText(result.text);
        setOutputRichHtml(result.html);
        setStats(result.stats);
        setActiveFact(randomFact);
        setViewMode('formatted');
        setIsProcessing(false);
    }, 400);
  };

  const handleCopyRich = async () => {
    try {
        const richContent = outputFormattedRef.current?.innerHTML || outputRichHtml;
        const wordHtml = getWordFriendlyHtml(richContent);
        const data = [new ClipboardItem({
            'text/html': new Blob([wordHtml], { type: 'text/html' }),
            'text/plain': new Blob([outputText], { type: 'text/plain' }),
        })];
        await navigator.clipboard.write(data);
        setCopied('rich');
        setTimeout(() => setCopied(null), 2000);
    } catch (err) {
        handleCopyPlain();
    }
  };

  const handleCopyPlain = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-8 max-w-4xl mx-auto pb-20 overflow-x-hidden">

      {/* INPUT AREA */}
      <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col overflow-hidden transition-all hover:shadow-md">
        <div className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800 px-5 py-3 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <Languages size={16} className="text-blue-500" />
                <span className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">טקסט מקור (ChatGPT / Claude)</span>
            </div>
            <div className="flex gap-4">
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors text-xs flex items-center gap-1.5">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'תצוגת קוד'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText(''); setOutputRichHtml(''); setStats(null); setActiveFact(null);}} className="text-xs text-slate-400 hover:text-red-500 flex items-center gap-1.5 transition-colors">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[180px] p-6 text-lg leading-relaxed text-slate-800 dark:text-slate-200 focus:outline-none max-h-[400px] overflow-y-auto"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
      </div>

      {/* ACTION BUTTON */}
      <div className="flex justify-center -my-4 z-10 relative">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-4.5 rounded-full shadow-xl flex items-center gap-3 font-black transition-all active:scale-95 hover:scale-105 disabled:opacity-70 group overflow-hidden"
         >
            <div className={`absolute inset-0 bg-white/20 transition-transform duration-1000 ${isProcessing ? 'translate-x-full' : '-translate-x-full'}`} />
            {isProcessing ? <span className="animate-spin text-xl">⌛</span> : <Wand2 size={24} className="group-hover:rotate-12 transition-transform" />}
            תיקון כיווניות עמוק
         </button>
      </div>

      {/* OUTPUT AREA */}
      <div className="flex flex-col gap-4">
          <div className="flex justify-between items-end px-1">
              <div className="flex gap-1 bg-slate-200/50 dark:bg-slate-800/50 p-1 rounded-lg">
                  <button onClick={() => setViewMode('formatted')} className={`px-5 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'formatted' ? 'bg-white dark:bg-slate-700 text-blue-700 dark:text-blue-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>
                      תצוגה מקדימה
                  </button>
                  <button onClick={() => setViewMode('raw')} className={`px-5 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'raw' ? 'bg-white dark:bg-slate-700 text-blue-700 dark:text-blue-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>
                      קוד UTF-8 (Plain)
                  </button>
              </div>
          </div>

          <div className="bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-800 rounded-2xl overflow-hidden shadow-lg relative min-h-[200px] transition-all">
             {viewMode === 'raw' ? (
                 <div className="p-6 font-mono text-sm text-slate-600 dark:text-slate-400 bg-slate-50/50 dark:bg-slate-950/50 min-h-[200px] whitespace-pre-wrap overflow-x-auto select-all" dir="ltr">
                     {outputText}
                 </div>
             ) : (
                 <div 
                    ref={outputFormattedRef}
                    contentEditable
                    className="p-8 text-slate-900 dark:text-slate-100 text-xl leading-relaxed min-h-[200px] focus:outline-none selection:bg-blue-100 dark:selection:bg-blue-900/40"
                    dir="rtl"
                    dangerouslySetInnerHTML={{ __html: outputRichHtml }}
                 />
             )}

             {!outputRichHtml && !outputText && !isProcessing && (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 pointer-events-none p-10 text-center gap-4">
                    <div className="w-16 h-16 rounded-full border-2 border-dashed border-slate-200 dark:border-slate-800 flex items-center justify-center">
                        <Info size={24} />
                    </div>
                    <span className="italic font-medium text-slate-400 dark:text-slate-600">התוצאה המעובדת תופיע כאן...</span>
                </div>
             )}
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
               <button
                    onClick={handleCopyRich}
                    disabled={!outputRichHtml && !outputText}
                    className={`flex-[2] flex items-center justify-center gap-3 py-5 rounded-2xl font-black transition-all shadow-xl active:translate-y-1 active:shadow-md disabled:bg-slate-100 dark:disabled:bg-slate-800 disabled:text-slate-400 ${copied === 'rich' ? 'bg-emerald-500 text-white' : 'bg-slate-900 dark:bg-blue-600 text-white hover:bg-black dark:hover:bg-blue-500'}`}
               >
                    {copied === 'rich' ? <Check size={22} className="animate-in zoom-in" /> : <ClipboardCheck size={22} />}
                    {copied === 'rich' ? 'הועתק ל-Word!' : 'העתקה מעוצבת למסמך'}
               </button>

               <button
                    onClick={handleCopyPlain}
                    disabled={!outputText}
                    className={`flex-1 flex items-center justify-center gap-2 py-5 rounded-2xl font-bold transition-all border-2 active:translate-y-1 ${copied === 'plain' ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-500 text-emerald-700 dark:text-emerald-400' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-300 hover:border-slate-300 dark:hover:border-slate-700 shadow-sm'}`}
               >
                    {copied === 'plain' ? <Check size={20} /> : <ClipboardCopy size={20} />}
                    טקסט בלבד
               </button>
          </div>
      </div>

      {/* DASHBOARD & FACTS SECTION - STABILIZED WITH DARK MODE */}
      <div className={`transition-all duration-700 ease-in-out overflow-hidden ${stats ? 'max-h-[1200px] opacity-100 mt-6' : 'max-h-0 opacity-0 pointer-events-none'}`}>
          <div className="space-y-6">

              {/* Analysis Header */}
              <div className="flex items-center gap-3 px-1">
                  <div className="h-px bg-slate-200 dark:bg-slate-800 flex-1" />
                  <div className="flex items-center gap-2 text-slate-400 dark:text-slate-600 font-bold text-[10px] uppercase tracking-widest px-3">
                      <BarChart3 size={14} /> נתוני עיבוד וניתוח שפה
                  </div>
                  <div className="h-px bg-slate-200 dark:bg-slate-800 flex-1" />
              </div>

              {/* Stats Grid */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center group hover:border-blue-200 dark:hover:border-blue-800 transition-colors">
                      <Hash size={24} className="text-slate-300 dark:text-slate-600 mb-2 group-hover:text-blue-400 transition-colors" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{stats?.totalChars || 0}</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">תווים</span>
                  </div>
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center group hover:border-blue-200 dark:hover:border-blue-800 transition-colors">
                      <ArrowRightLeft size={24} className="text-blue-500 mb-2 group-hover:scale-110 transition-transform" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{stats?.replaced || 0}</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">החלפות</span>
                  </div>
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center group hover:border-amber-200 dark:hover:border-amber-800 transition-colors">
                      <Zap size={24} className="text-amber-500 mb-2 group-hover:scale-110 transition-transform" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{stats?.anchored || 0}</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">RLM</span>
                  </div>
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center group hover:border-emerald-200 dark:hover:border-emerald-800 transition-colors overflow-hidden relative">
                      <div className="absolute top-0 right-0 w-12 h-12 bg-emerald-50 dark:bg-emerald-900/20 rounded-bl-full -mr-4 -mt-4 opacity-50 group-hover:scale-150 transition-transform" />
                      <Sparkles size={24} className="text-emerald-500 mb-2 group-hover:scale-110 transition-transform" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{(stats?.interventionRate || 0).toFixed(1)}%</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">ייעול</span>
                  </div>
              </div>

              {/* Fact Card */}
              {activeFact && (
                  <div className="bg-white dark:bg-slate-900 border border-blue-100 dark:border-blue-900/30 p-6 rounded-2xl shadow-sm flex flex-col md:flex-row gap-5 items-center md:items-start group transition-all hover:shadow-md hover:border-blue-200 dark:hover:border-blue-800 relative overflow-hidden">
                      <div className="bg-blue-600 dark:bg-blue-500 p-3.5 rounded-2xl text-white shadow-lg shadow-blue-100 dark:shadow-blue-950 shrink-0 group-hover:rotate-6 transition-transform z-10">
