                  <div className="w-1.5 h-1.5 bg-slate-400 dark:bg-slate-600 rounded-full" />
              </div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Code2, Sparkles, LayoutTemplate, FileText, Info, Sun, Moon } from 'lucide-react';
import { C_CODE_TEMPLATE } from './constants';
import { BidiFixer } from './components/BidiFixer';
import { explainCodeLogic } from './services/geminiService';

