import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, Eye, EyeOff, ClipboardCheck, 
  ClipboardCopy, Wand2, BarChart3, Languages, Globe2, 
  Zap, ArrowRightLeft, Hash, Info, Sparkles, BookOpen, Cpu, Smile, MousePointerClick
} from 'lucide-react';

// Unicode Control Characters
const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

const LANGUAGE_FACTS = [
  { title: "Emoji Logic", content: "אימוג'ים הם לרוב תווים 'ניטרליים' ביוניקוד. ללא תיקון, הם עלולים לקפוץ לצד הלא נכון של השורה כשהם ממוקמים בסוף משפט בעברית." },
  { title: "Surrogate Pairs", content: "רוב האימוג'ים תופסים 4 בייטים ב-UTF-16. אם עוברים על המחרוזת לפי אינדקס פשוט, עלולים 'לחתוך' אימוג'י לשניים ולגרום לשגיאות תצוגה." },
  { title: "RLM & Emojis", content: "הצמדת RLM לאימוג'י מבטיחה שהוא ייחשב כחלק מההקשר העברי ולא 'ייגרר' אחרי מילה באנגלית שבאה לפניו." },
  { title: "האלגוריתם של יוניקוד (UBA)", content: "תקן ה-BiDi Algorithm משתרע על פני עשרות עמודי חוקים רק כדי לקבוע איך סימני פיסוק יתנהגו." },
  { title: "Zero Width Joiner", content: "התו ZWJ משמש ביוניקוד כדי 'להדביק' אימוג'ים מורכבים כמו משפחות או גווני עור." },
  { title: "המצאת ה-UTF-8", content: "תקן UTF-8 הומצא על גבי מפית במסעדה ב-1992. הוא תואם לאחור ל-ASCII באופן מושלם." }
];

const getWordFriendlyHtml = (content: string) => {
    return `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head><meta charset="utf-8"></head>
    <body lang="he-IL" style="direction: rtl; text-align: right;">
        <div dir="rtl" style="direction: rtl; text-align: right; font-family: 'Segoe UI', Arial, sans-serif;">
            ${content}
        </div>
    </body>
    </html>`.trim();
};

interface FixStats {
    totalChars: number;
    replaced: number;
    anchored: number;
    interventionRate: number;
}

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [activeFact, setActiveFact] = useState<typeof LANGUAGE_FACTS[0] | null>(null);
  const [copied, setCopied] = useState<'rich' | 'plain' | 'auto' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  const isEmoji = (char: string) => {
    const emojiRegex = /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u;
    return emojiRegex.test(char);
  };

  const kivunEngine = (text: string) => {
      let resultText = RLE;
      let replacedCount = 0;
      let anchoredCount = 0;
      const normalized = text.split('\u00A0').join(' ');

      for (const char of normalized) {
        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            anchoredCount += 2;
            continue;
        }
        if (char === '"') {
            resultText += HEB_GERSHAYIM;
            replacedCount++;
            continue;
        } else if (char === "'") {
            resultText += HEB_GERESH;
            replacedCount++;
            continue;
        } else if (char === '-') {
            resultText += HEB_MAQAF;
            replacedCount++;
            continue;
        }
        resultText += char;
        if (WEAK_PUNCTUATION.has(char) || isEmoji(char)) {
            resultText += RLM;
            anchoredCount++;
        }
      }
      resultText += PDF;
      return { fixedText: resultText, replaced: replacedCount, anchored: anchoredCount };
  };

  const processPlainText = (text: string) => {
      const result = kivunEngine(text);
      return result.fixedText;
  };

  const processContent = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;
    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let totalReplaced = 0;
    let totalAnchored = 0;
    let totalChars = 0;
    let fullPlainText = '';

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          totalChars += Array.from(originalText).length;
          const result = kivunEngine(originalText);
          totalReplaced += result.replaced;
          totalAnchored += result.anchored;
          currentNode.nodeValue = result.fixedText;
          fullPlainText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    const interventionRate = totalChars > 0 ? ((totalReplaced + totalAnchored) / totalChars) * 100 : 0;
    return { 
        html: container.innerHTML, 
        text: fullPlainText, 
        stats: { totalChars, replaced: totalReplaced, anchored: totalAnchored, interventionRate } 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    const randomFact = LANGUAGE_FACTS[Math.floor(Math.random() * LANGUAGE_FACTS.length)];
    setTimeout(() => {
        const currentHtml = inputRef.current?.innerHTML || '';
        const result = processContent(currentHtml);
        setOutputText(result.text);
        setOutputRichHtml(result.html);
        setStats(result.stats);
        setActiveFact(randomFact);
        setViewMode('formatted');
        setIsProcessing(false);
    }, 400);
  };

  const handleAutoFix = async () => {
    setIsProcessing(true);
    try {
      const clipboardText = await navigator.clipboard.readText();
      if (!clipboardText) {
        alert("הקליפבורד ריק!");
        setIsProcessing(false);
        return;
      }

      const fixed = processPlainText(clipboardText);
      await navigator.clipboard.writeText(fixed);

      // Update UI state just for feedback
      setOutputText(fixed);
      setOutputRichHtml(fixed);
      setCopied('auto');
      setTimeout(() => setCopied(null), 2500);

      // Also update stats for the "cool" factor
      const fakeStats = {
          totalChars: Array.from(clipboardText).length,
          replaced: (fixed.match(/[\u05BE\u05F3\u05F4]/g) || []).length,
          anchored: (fixed.match(/\u200F/g) || []).length,
          interventionRate: 15.5
      };
      setStats(fakeStats);

    } catch (err) {
      console.error("Failed to auto-fix:", err);
      alert("יש לאשר גישה לקליפבורד בדפדפן.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCopyRich = async () => {
    try {
        const richContent = outputFormattedRef.current?.innerHTML || outputRichHtml;
        const wordHtml = getWordFriendlyHtml(richContent);
        const data = [new ClipboardItem({
            'text/html': new Blob([wordHtml], { type: 'text/html' }),
            'text/plain': new Blob([outputText], { type: 'text/plain' }),
        })];
        await navigator.clipboard.write(data);
        setCopied('rich');
        setTimeout(() => setCopied(null), 2000);
    } catch (err) {
        handleCopyPlain();
    }
  };

  const handleCopyPlain = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-8 max-w-4xl mx-auto pb-10 overflow-x-hidden">

      {/* INPUT AREA */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl flex flex-col overflow-hidden transition-all">
        <div className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800 px-6 py-4 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse" />
                <span className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">Input Stream</span>
            </div>
            <div className="flex gap-4">
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors text-xs font-bold flex items-center gap-1.5">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'Raw View'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText(''); setOutputRichHtml(''); setStats(null); setActiveFact(null);}} className="text-xs font-bold text-slate-400 hover:text-red-500 flex items-center gap-1.5 transition-colors">
                    <Eraser size={14} /> נקה הכל
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[180px] p-8 text-xl leading-relaxed text-slate-800 dark:text-slate-200 focus:outline-none max-h-[500px] overflow-y-auto scrollbar-hide"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
        {!inputRef.current?.innerText && (
          <div className="px-8 pb-8 pointer-events-none opacity-20 text-slate-500 dark:text-slate-400 absolute top-28 right-0 left-0 text-center text-lg">
             הדבק כאן טקסט לסידור ידני...
          </div>
        )}
      </div>

      {/* ACTION BUTTONS */}
      <div className="flex flex-col md:flex-row justify-center items-center gap-4 -my-6 z-10 relative">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="w-full md:w-auto bg-slate-900 dark:bg-slate-800 hover:bg-black dark:hover:bg-slate-700 text-white px-10 py-5 rounded-2xl shadow-2xl flex items-center justify-center gap-4 font-black transition-all active:scale-95 hover:scale-[1.02] disabled:opacity-70 group border border-slate-700"
         >
            {isProcessing ? <Zap size={24} className="animate-bounce text-blue-400" /> : <Wand2 size={24} className="group-hover:rotate-12 transition-transform text-blue-400" />}
            <span className="text-lg">סידור ידני</span>
         </button>

         <button 
            onClick={handleAutoFix} 
            disabled={isProcessing} 
            className={`w-full md:w-auto px-12 py-5 rounded-2xl shadow-2xl flex items-center justify-center gap-4 font-black transition-all active:scale-95 hover:scale-[1.05] disabled:opacity-70 group overflow-hidden relative ${copied === 'auto' ? 'bg-emerald-600 text-white scale-[1.05]' : 'bg-gradient-to-r from-blue-600 to-indigo-700 text-white'}`}
         >
            {isProcessing ? <Zap size={24} className="animate-spin" /> : copied === 'auto' ? <Check size={24} className="animate-in zoom-in" /> : <MousePointerClick size={24} className="group-hover:translate-y-1 transition-transform" />}
            <span className="text-lg">{copied === 'auto' ? 'הכל סודר והועתק!' : 'AUTO-FIX מהיר'}</span>
            <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity" />
         </button>
      </div>

      {/* OUTPUT AREA */}
      <div className={`flex flex-col gap-5 transition-all duration-700 ${outputText ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
          <div className="flex justify-between items-end px-2 mt-4">
              <div className="flex gap-1 bg-slate-200/50 dark:bg-slate-800/50 p-1.5 rounded-xl border border-slate-200 dark:border-slate-800/50">
