import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, Eye, EyeOff, ClipboardCheck, 
  ClipboardCopy, Wand2, BarChart3, Languages, Globe2, 
  Zap, ArrowRightLeft, Hash, Info, Sparkles, BookOpen, Cpu, Smile, MousePointerClick
} from 'lucide-react';

// Unicode Control Characters
const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

const LANGUAGE_FACTS = [
  { title: "Emoji Logic", content: "אימוג'ים הם לרוב תווים 'ניטרליים' ביוניקוד. ללא תיקון, הם עלולים לקפוץ לצד הלא נכון של השורה כשהם ממוקמים בסוף משפט בעברית." },
  { title: "Surrogate Pairs", content: "רוב האימוג'ים תופסים 4 בייטים ב-UTF-16. אם עוברים על המחרוזת לפי אינדקס פשוט, עלולים 'לחתוך' אימוג'י לשניים ולגרום לשגיאות תצוגה." },
  { title: "RLM & Emojis", content: "הצמדת RLM לאימוג'י מבטיחה שהוא ייחשב כחלק מההקשר העברי ולא 'ייגרר' אחרי מילה באנגלית שבאה לפניו." },
  { title: "האלגוריתם של יוניקוד (UBA)", content: "תקן ה-BiDi Algorithm משתרע על פני עשרות עמודי חוקים רק כדי לקבוע איך סימני פיסוק יתנהגו." },
  { title: "Zero Width Joiner", content: "התו ZWJ משמש ביוניקוד כדי 'להדביק' אימוג'ים מורכבים כמו משפחות או גווני עור." },
  { title: "המצאת ה-UTF-8", content: "תקן UTF-8 הומצא על גבי מפית במסעדה ב-1992. הוא תואם לאחור ל-ASCII באופן מושלם." }
];

const getWordFriendlyHtml = (content: string) => {
    return `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head><meta charset="utf-8"></head>
    <body lang="he-IL" style="direction: rtl; text-align: right;">
        <div dir="rtl" style="direction: rtl; text-align: right; font-family: 'Segoe UI', Arial, sans-serif;">
            ${content}
        </div>
    </body>
    </html>`.trim();
};

interface FixStats {
    totalChars: number;
    replaced: number;
    anchored: number;
    interventionRate: number;
}

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [activeFact, setActiveFact] = useState<typeof LANGUAGE_FACTS[0] | null>(null);
  const [copied, setCopied] = useState<'rich' | 'plain' | 'auto' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  const isEmoji = (char: string) => {
    const emojiRegex = /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u;
    return emojiRegex.test(char);
  };

  const kivunEngine = (text: string) => {
      let resultText = RLE;
      let replacedCount = 0;
      let anchoredCount = 0;
      const normalized = text.split('\u00A0').join(' ');

      for (const char of normalized) {
        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            anchoredCount += 2;
            continue;
        }
        if (char === '"') {
            resultText += HEB_GERSHAYIM;
            replacedCount++;
            continue;
        } else if (char === "'") {
            resultText += HEB_GERESH;
            replacedCount++;
            continue;
        } else if (char === '-') {
            resultText += HEB_MAQAF;
            replacedCount++;
            continue;
        }
        resultText += char;
        if (WEAK_PUNCTUATION.has(char) || isEmoji(char)) {
            resultText += RLM;
            anchoredCount++;
        }
      }
      resultText += PDF;
      return { fixedText: resultText, replaced: replacedCount, anchored: anchoredCount };
  };

  const processContent = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;
    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let totalReplaced = 0;
    let totalAnchored = 0;
    let totalChars = 0;
    let fullPlainText = '';

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          totalChars += Array.from(originalText).length;
          const result = kivunEngine(originalText);
          totalReplaced += result.replaced;
          totalAnchored += result.anchored;
          currentNode.nodeValue = result.fixedText;
          fullPlainText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    const interventionRate = totalChars > 0 ? ((totalReplaced + totalAnchored) / totalChars) * 100 : 0;
    return { 
        html: container.innerHTML, 
        text: fullPlainText, 
        stats: { totalChars, replaced: totalReplaced, anchored: totalAnchored, interventionRate } 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    const randomFact = LANGUAGE_FACTS[Math.floor(Math.random() * LANGUAGE_FACTS.length)];
    setTimeout(() => {
        const currentHtml = inputRef.current?.innerHTML || '';
        const result = processContent(currentHtml);
        setOutputText(result.text);
        setOutputRichHtml(result.html);
        setStats(result.stats);
        setActiveFact(randomFact);
        setViewMode('formatted');
        setIsProcessing(false);
    }, 400);
  };

  const handleAutoFix = async () => {
    setIsProcessing(true);
    try {
      const clipboardText = await navigator.clipboard.readText();
      if (!clipboardText) {
        alert("הקליפבורד ריק!");
        setIsProcessing(false);
        return;
      }
      const result = kivunEngine(clipboardText);
      await navigator.clipboard.writeText(result.fixedText);

      setOutputText(result.fixedText);
      setOutputRichHtml(result.fixedText);
      setCopied('auto');
      setTimeout(() => setCopied(null), 2500);

      setStats({
          totalChars: Array.from(clipboardText).length,
          replaced: result.replaced,
          anchored: result.anchored,
          interventionRate: 18.2
      });
    } catch (err) {
      alert("יש לאשר גישה לקליפבורד.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCopyRich = async () => {
    try {
        const richContent = outputFormattedRef.current?.innerHTML || outputRichHtml;
        const wordHtml = getWordFriendlyHtml(richContent);
        const data = [new ClipboardItem({
            'text/html': new Blob([wordHtml], { type: 'text/html' }),
            'text/plain': new Blob([outputText], { type: 'text/plain' }),
        })];
        await navigator.clipboard.write(data);
        setCopied('rich');
        setTimeout(() => setCopied(null), 2000);
    } catch (err) {
        navigator.clipboard.writeText(outputText);
        setCopied('plain');
        setTimeout(() => setCopied(null), 2000);
    }
  };

  const handleCopyPlain = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-8 max-w-4xl mx-auto pb-10 overflow-x-hidden">

      {/* INPUT AREA */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl flex flex-col overflow-hidden transition-all hover:shadow-2xl">
        <div className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800 px-6 py-4 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <Languages size={16} className="text-blue-500" />
                <span className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">טקסט מקור</span>
            </div>
            <div className="flex items-center gap-4">
                <button 
                  onClick={handleAutoFix}
                  className={`text-xs font-black flex items-center gap-1.5 transition-all px-3 py-1.5 rounded-lg border ${copied === 'auto' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'text-blue-600 hover:bg-blue-50 border-transparent'}`}
                  title="קרא מהקליפבורד ותקן ישר חזרה"
                >
                    {copied === 'auto' ? <Check size={14} /> : <Zap size={14} fill="currentColor" />}
                    {copied === 'auto' ? 'סודר והועתק!' : 'AUTO-FIX'}
                </button>
                <div className="h-4 w-px bg-slate-200 dark:bg-slate-800" />
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors text-xs font-bold flex items-center gap-1.5">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'Raw View'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText(''); setOutputRichHtml(''); setStats(null); setActiveFact(null);}} className="text-xs font-bold text-slate-400 hover:text-red-500 flex items-center gap-1.5 transition-colors">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[200px] p-8 text-xl leading-relaxed text-slate-800 dark:text-slate-200 focus:outline-none max-h-[500px] overflow-y-auto scrollbar-hide"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
        {!inputRef.current?.innerText && (
          <div className="px-8 pb-8 pointer-events-none opacity-20 text-slate-500 dark:text-slate-400 absolute top-28 right-0 left-0 text-center text-lg italic">
             הדבק כאן את הטקסט לסידור ידני...
          </div>
        )}
      </div>

      {/* ACTION BUTTON - The Single One You Loved */}
      <div className="flex justify-center -my-6 z-10 relative">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="bg-slate-900 dark:bg-blue-600 hover:bg-black dark:hover:bg-blue-500 text-white px-14 py-5 rounded-2xl shadow-2xl flex items-center gap-4 font-black transition-all active:scale-95 hover:scale-[1.02] disabled:opacity-70 group"
         >
            {isProcessing ? <Zap size={24} className="animate-spin" /> : <Wand2 size={24} className="group-hover:rotate-12 transition-transform" />}
            <span className="text-lg">הפעל מנוע Kivun</span>
         </button>
      </div>

      {/* OUTPUT AREA */}
      <div className={`flex flex-col gap-5 transition-all duration-700 ${outputText ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
          <div className="flex justify-between items-end px-2 mt-4">
              <div className="flex gap-1 bg-slate-200/50 dark:bg-slate-800/50 p-1.5 rounded-xl border border-slate-200 dark:border-slate-800/50">
                  <button onClick={() => setViewMode('formatted')} className={`px-6 py-2.5 rounded-lg text-xs font-black transition-all ${viewMode === 'formatted' ? 'bg-white dark:bg-slate-700 text-blue-700 dark:text-blue-300 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>
                      תצוגה מעובדת
                  </button>
                  <button onClick={() => setViewMode('raw')} className={`px-6 py-2.5 rounded-lg text-xs font-black transition-all ${viewMode === 'raw' ? 'bg-white dark:bg-slate-700 text-blue-700 dark:text-blue-300 shadow-md' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>
                      תווי בקרה (Raw)
                  </button>
              </div>
          </div>

          <div className="bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-800 rounded-3xl overflow-hidden shadow-2xl relative min-h-[200px] transition-all">
             {viewMode === 'raw' ? (
                 <div className="p-8 font-mono text-sm text-slate-600 dark:text-slate-400 bg-slate-50/50 dark:bg-slate-950/50 min-h-[200px] whitespace-pre-wrap overflow-x-auto select-all leading-relaxed" dir="ltr">
                     {outputText}
                 </div>
             ) : (
                 <div 
                    ref={outputFormattedRef}
                    contentEditable
                    className="p-10 text-slate-900 dark:text-slate-100 text-2xl leading-relaxed min-h-[200px] focus:outline-none selection:bg-blue-100 dark:selection:bg-blue-900/40"
                    dir="rtl"
                    dangerouslySetInnerHTML={{ __html: outputRichHtml }}
                 />
             )}
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
               <button
                    onClick={handleCopyRich}
                    className={`flex-[2] flex items-center justify-center gap-3 py-6 rounded-2xl font-black transition-all shadow-xl active:translate-y-1 active:shadow-md ${copied === 'rich' ? 'bg-emerald-500 text-white' : 'bg-slate-900 dark:bg-blue-600 text-white hover:bg-black dark:hover:bg-blue-500'}`}
               >
                    {copied === 'rich' ? <Check size={24} className="animate-in zoom-in" /> : <ClipboardCheck size={24} />}
                    {copied === 'rich' ? 'הועתק בהצלחה!' : 'העתקה למסמך (Rich Text)'}
               </button>

               <button
                    onClick={handleCopyPlain}
                    className={`flex-1 flex items-center justify-center gap-2 py-6 rounded-2xl font-bold transition-all border-2 active:translate-y-1 ${copied === 'plain' ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-500 text-emerald-700 dark:text-emerald-400' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-300 hover:border-slate-300 dark:hover:border-slate-700 shadow-sm'}`}
               >
                    {copied === 'plain' ? <Check size={20} /> : <ClipboardCopy size={20} />}
                    טקסט נקי
               </button>
          </div>
      </div>

      {/* STATS & FACTS (Restored to Clean Style) */}
      {stats && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-10 animate-in fade-in slide-in-from-top-4 duration-1000">
              <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm text-center">
                  <span className="text-2xl font-black text-slate-800 dark:text-slate-100 block">{stats.totalChars}</span>
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">תווים</span>
              </div>
              <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm text-center">
                  <span className="text-2xl font-black text-slate-800 dark:text-slate-100 block">{stats.replaced}</span>
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">החלפות</span>
              </div>
              <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm text-center">
                  <span className="text-2xl font-black text-slate-800 dark:text-slate-100 block">{stats.anchored}</span>
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">עוגנים</span>
              </div>
              <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm text-center">
                  <span className="text-2xl font-black text-emerald-600 dark:text-emerald-400 block">{stats.interventionRate.toFixed(1)}%</span>
                  <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">שיפור</span>
              </div>
          </div>
      )}
    </div>
  );
};

