import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, Eye, EyeOff, ClipboardCheck, 
  ClipboardCopy, Wand2, Zap, Languages
} from 'lucide-react';

const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

const HEB_MAQAF = '\u05BE';
const HEB_GERESH = '\u05F3';
const HEB_GERSHAYIM = '\u05F4';

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [copied, setCopied] = useState<'rich' | 'plain' | 'auto' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);

  const inputRef = useRef<HTMLDivElement>(null);

  const isEmoji = (char: string) => {
    return /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u.test(char);
  };

  const kivunEngine = (text: string) => {
      let resultText = RLE;
      const normalized = text.split('\u00A0').join(' ');

      for (const char of normalized) {
        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            continue;
        }
        if (char === '"') { resultText += HEB_GERSHAYIM; continue; }
        if (char === "'") { resultText += HEB_GERESH; continue; }
        if (char === '-') { resultText += HEB_MAQAF; continue; }

        resultText += char;
        if (WEAK_PUNCTUATION.has(char) || isEmoji(char)) {
            resultText += RLM;
        }
      }
      resultText += PDF;
      return resultText;
  };

  const handleFix = () => {
    setIsProcessing(true);
    setTimeout(() => {
        const text = inputRef.current?.innerText || '';
        setOutputText(kivunEngine(text));
        setIsProcessing(false);
    }, 200);
  };

  const handleAutoFix = async () => {
    try {
      const clipboardText = await navigator.clipboard.readText();
      if (!clipboardText) return;
      const fixed = kivunEngine(clipboardText);
      await navigator.clipboard.writeText(fixed);
      setOutputText(fixed);
      setCopied('auto');
      setTimeout(() => setCopied(null), 2000);
    } catch (err) {
      alert("נדרשת גישה לקליפבורד");
    }
  };

  const copyToClipboard = (text: string, type: 'rich' | 'plain') => {
    navigator.clipboard.writeText(text);
    setCopied(type);
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-6">

      {/* Input Box */}
      <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden transition-all focus-within:ring-2 ring-blue-500/20">
        <div className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800 px-5 py-3 flex justify-between items-center">
            <div className="flex items-center gap-2 text-slate-400">
                <Languages size={14} />
                <span className="text-[10px] font-black uppercase tracking-widest">Input</span>
            </div>
            <div className="flex items-center gap-3">
                <button 
                  onClick={handleAutoFix}
                  className={`text-[10px] font-black flex items-center gap-1.5 px-2 py-1 rounded border transition-colors ${copied === 'auto' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'text-blue-600 border-transparent hover:bg-blue-50'}`}
                >
                    {copied === 'auto' ? <Check size={12} /> : <Zap size={12} fill="currentColor" />}
                    {copied === 'auto' ? 'COPIED!' : 'AUTO-FIX'}
                </button>
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-slate-600 text-[10px] font-bold">
                    {showRawInput ? 'LTR' : 'RTL'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerText = ''; setOutputText('');}} className="text-slate-400 hover:text-red-500">
                    <Eraser size={14} />
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="p-6 text-xl min-h-[150px] focus:outline-none dark:text-slate-200"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
        />
      </div>

      {/* Main Fix Button */}
