import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, Eye, EyeOff, ClipboardCopy, Wand2, Zap, Languages
} from 'lucide-react';

const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

const HEB_MAQAF = '\u05BE';
const HEB_GERESH = '\u05F3';
const HEB_GERSHAYIM = '\u05F4';

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [copied, setCopied] = useState<'plain' | 'auto' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);

  const inputRef = useRef<HTMLDivElement>(null);

  // Improved emoji detection supporting complex sequences
  const isEmoji = (char: string) => {
    return /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u.test(char);
  };

  const kivunEngine = (text: string) => {
      // Start with RTL Embedding
      let resultText = RLE;
      const normalized = text.split('\u00A0').join(' ');

      // Use for...of to correctly iterate over Unicode code points (handling emojis)
      for (const char of normalized) {
        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            continue;
        }

        // Logical replacements
        if (char === '"') { resultText += HEB_GERSHAYIM; continue; }
        if (char === "'") { resultText += HEB_GERESH; continue; }
        if (char === '-') { resultText += HEB_MAQAF; continue; }

        resultText += char;

        // Anchor weak punctuation and emojis with RLM to prevent jumping sides
        if (WEAK_PUNCTUATION.has(char) || isEmoji(char)) {
            resultText += RLM;
        }
      }

      // Close RTL Embedding
      resultText += PDF;
      return resultText;
  };

  const handleFix = () => {
    setIsProcessing(true);
    setTimeout(() => {
        const text = inputRef.current?.innerText || '';
        if (text.trim()) {
            setOutputText(kivunEngine(text));
        }
        setIsProcessing(false);
    }, 200);
  };

  const handleAutoFix = async () => {
    try {
      const clipboardText = await navigator.clipboard.readText();
      if (!clipboardText) return;
      const fixed = kivunEngine(clipboardText);
      await navigator.clipboard.writeText(fixed);
      setOutputText(fixed);
      setCopied('auto');
      setTimeout(() => setCopied(null), 2500);
    } catch (err) {
      alert("יש לאשר גישה לקליפבורד בהגדרות הדפדפן.");
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-6">

      {/* Input Box */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl overflow-hidden transition-all focus-within:ring-2 ring-blue-500/20">
        <div className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800 px-6 py-4 flex justify-between items-center">
            <div className="flex items-center gap-2 text-slate-400">
                <Languages size={16} />
                <span className="text-[11px] font-black uppercase tracking-widest">טקסט מקור</span>
            </div>
            <div className="flex items-center gap-4">
                <button 
                  onClick={handleAutoFix}
                  className={`text-[11px] font-black flex items-center gap-1.5 px-3 py-1.5 rounded-lg border transition-all ${copied === 'auto' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'text-blue-600 border-transparent hover:bg-blue-50 dark:hover:bg-blue-900/20'}`}
                  title="תיקון מהיר ישירות מהקליפבורד"
                >
                    {copied === 'auto' ? <Check size={14} /> : <Zap size={14} fill="currentColor" />}
                    {copied === 'auto' ? 'COPIED!' : 'AUTO-FIX'}
                </button>
                <div className="w-px h-4 bg-slate-200 dark:bg-slate-800" />
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 text-[11px] font-bold">
                    {showRawInput ? 'תצוגת LTR' : 'תצוגת RTL'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerText = ''; setOutputText('');}} className="text-slate-400 hover:text-red-500 transition-colors">
                    <Eraser size={16} />
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="p-8 text-2xl min-h-[220px] focus:outline-none dark:text-slate-100 leading-relaxed scrollbar-hide overflow-y-auto"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
      </div>

      {/* Main Fix Button */}
      <div className="flex justify-center -my-3 z-10">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="bg-slate-900 dark:bg-blue-600 hover:bg-black dark:hover:bg-blue-500 text-white px-12 py-5 rounded-2xl shadow-2xl flex items-center gap-4 font-black transition-all active:scale-95 disabled:opacity-50 group border border-transparent hover:border-blue-400/30"
         >
