} from 'lucide-react';

const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

const HEB_MAQAF = '\u05BE';
const HEB_GERESH = '\u05F3';
const HEB_GERSHAYIM = '\u05F4';

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [copied, setCopied] = useState<'plain' | 'auto' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const inputRef = useRef<HTMLDivElement>(null);

  // Advanced emoji detection
  const isEmoji = (char: string) => {
    return /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u.test(char);
  };

  const processText = (text: string) => {
      let resultText = RLE;
      const normalized = text.split('\u00A0').join(' ');

      // iterate via code points to handle emojis correctly
      for (const char of normalized) {
        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            continue;
        }

        if (char === '"') { resultText += HEB_GERSHAYIM; continue; }
        if (char === "'") { resultText += HEB_GERESH; continue; }
        if (char === '-') { resultText += HEB_MAQAF; continue; }

        resultText += char;

        if (WEAK_PUNCTUATION.has(char) || isEmoji(char)) {
            resultText += RLM;
        }
      }

      resultText += PDF;
      return resultText;
  };

  const handleFix = () => {
    setIsProcessing(true);
    setTimeout(() => {
        const text = inputRef.current?.innerText || '';
        if (text.trim()) {
            setOutputText(processText(text));
        }
        setIsProcessing(false);
    }, 200);
  };

  const handleAutoFix = async () => {
    try {
      const clipboardText = await navigator.clipboard.readText();
      if (!clipboardText) return;
      const fixed = processText(clipboardText);
      await navigator.clipboard.writeText(fixed);
      setOutputText(fixed);
      setCopied('auto');
      setTimeout(() => setCopied(null), 2000);
    } catch (err) {
      alert("נדרשת גישה לקליפבורד");
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">

      {/* Input Container */}
      <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm transition-all focus-within:ring-2 ring-blue-500/10 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/50">
            <div className="flex items-center gap-2 text-slate-400 font-bold text-xs uppercase tracking-widest">
                <Languages size={14} />
                קלט טקסט
            </div>
            <div className="flex items-center gap-4">
                <button 
                  onClick={handleAutoFix}
                  className={`text-[10px] font-black flex items-center gap-1.5 px-3 py-1.5 rounded-lg transition-all ${copied === 'auto' ? 'bg-emerald-500 text-white' : 'text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20'}`}
                >
                    {copied === 'auto' ? <Check size={12} /> : <Zap size={12} fill="currentColor" />}
                    {copied === 'auto' ? 'COPIED!' : 'AUTO-FIX'}
                </button>
                <div className="w-px h-4 bg-slate-200 dark:bg-slate-800" />
                <button onClick={() => {if(inputRef.current) inputRef.current.innerText = ''; setOutputText('');}} className="p-1 text-slate-400 hover:text-red-500 transition-colors">
                    <Eraser size={16} />
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="p-8 text-2xl min-h-[200px] focus:outline-none dark:text-slate-100 leading-relaxed scrollbar-hide"
            dir="rtl"
            spellCheck={false}
        />
      </div>

      {/* Action Button */}
      <div className="flex justify-center -my-4 z-10 relative">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="bg-slate-900 dark:bg-blue-600 hover:bg-black dark:hover:bg-blue-500 text-white px-12 py-5 rounded-2xl shadow-xl flex items-center gap-4 font-black transition-all active:scale-95 disabled:opacity-50 border border-transparent hover:border-blue-400/20"
         >
            {isProcessing ? <Zap size={24} className="animate-spin" /> : <Wand2 size={24} />}
            <span className="text-lg">סדר את הטקסט</span>
         </button>
      </div>

      {/* Output Area */}
      {outputText && (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-6 duration-500">
          <div className="bg-white dark:bg-slate-900 border-2 border-blue-50 dark:border-blue-900/20 rounded-3xl p-8 text-3xl leading-relaxed shadow-lg dark:text-slate-50" dir="rtl">
             {outputText}
          </div>

          <button
              onClick={copyToClipboard}
              className={`w-full flex items-center justify-center gap-3 py-6 rounded-2xl font-black transition-all shadow-md active:translate-y-1 ${copied === 'plain' ? 'bg-emerald-500 text-white' : 'bg-slate-900 dark:bg-slate-800 text-white hover:bg-black'}`}
          >
              {copied === 'plain' ? <Check size={24} /> : <ClipboardCopy size={24} />}
              {copied === 'plain' ? 'הועתק בהצלחה!' : 'העתק תוצאה מסודרת'}
          </button>
        </div>
      )}
    </div>
  );
};

